package main

import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// deepCopy recursively copies JSON-compatible values to prevent mutation of original data.
// It handles map[string]interface{}, []interface{}, and primitive types (string, int, float, bool, nil).
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		newMap := make(map[string]interface{}, len(val))
		for k, v := range val {
			newMap[k] = deepCopy(v)
		}
		return newMap
	case []interface{}:
		newSlice := make([]interface{}, len(val))
		for i, v := range val {
			newSlice[i] = deepCopy(v)
		}
		return newSlice
	default:
		// Primitive types are passed by value, so no additional copy needed
		return val
	}
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Input items are not modified by the script, as a deep copy is passed to the JavaScript environment.
// Each script execution is fully isolated from others, with no shared state between iterations.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(items) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Create a single VM instance to avoid the high overhead of recreating VMs for each item
	vm := otto.New()

	// Capture initial global state to reset between iterations, ensuring execution isolation
	globalObjVal, err := vm.Get("this")
	if err != nil {
		return nil, fmt.Errorf("failed to access VM global object: %w", err)
	}
	globalObj := globalObjVal.Object()
	if globalObj == nil {
		return nil, fmt.Errorf("failed to get valid global object from VM")
	}
	originalGlobalKeys, err := globalObj.Keys()
	if err != nil {
		return nil, fmt.Errorf("failed to read initial global state: %w", err)
	}
	originalKeySet := make(map[string]bool, len(originalGlobalKeys))
	for _, key := range originalGlobalKeys {
		originalKeySet[key] = true
	}

	// Wrap condition script in a function to:
	// 1. Isolate variables to function scope (prevents accidental global leakage)
	// 2. Accept 'item' as a parameter, eliminating need for per-iteration global variable set
	// 3. Compile once and reuse across all items for better performance
	funcSource := fmt.Sprintf("(function(item) { %s })", conditionScript)
	filterFunc, err := vm.Run(funcSource)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}
	if !filterFunc.IsFunction() {
		return nil, fmt.Errorf("condition script did not evaluate to a valid function")
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Pass a deep copy of the item to the script to prevent mutation of original input data
		copiedItem := deepCopy(item).(map[string]interface{})

		// Execute the filter function with the copied item
		resultValue, err := filterFunc.Call(otto.NullValue(), copiedItem)

		// Reset global state to remove any variables added by the script before next iteration
		currentGlobalKeys, resetErr := globalObj.Keys()
		if resetErr != nil {
			return nil, fmt.Errorf("failed to read current global state: %w", resetErr)
		}
		for _, key := range currentGlobalKeys {
			if !originalKeySet[key] {
				if delErr := globalObj.Delete(key); delErr != nil {
					return nil, fmt.Errorf("failed to reset global state: %w", delErr)
				}
			}
		}

		// Handle script execution errors
		if err != nil {
			return nil, fmt.Errorf("failed to evaluate condition for item: %w", err)
		}

		// Convert result to boolean using native JavaScript truthiness rules
		boolResult, err := resultValue.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert condition result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

