func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const scriptTimeout = 1 * time.Second
	// Base VM with standard JS built-ins, cloned per item for efficiency and isolation
	baseVM := otto.New()
	// Compile the script once to avoid recompiling for each item
	script, err := baseVM.Compile("", conditionScript)
	if err!= nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}
	var result []map[string]interface{}
	for _, item := range items {
