		done := make(chan struct{})
		go func(vm *otto.Otto) {
			select {
			case <-time.After(scriptTimeout):
				vm.Interrupt <- func() {
					panic(fmt.Errorf("script execution timed out after %v", scriptTimeout))
				}
			case <-done:
